import React from 'react';
import axios from 'axios';
import '../assets/styles/MicrosoftTeams.css';

const MicrosoftTeamsButton = () => {
  const handleNavigation = (endpoint, actionName) => {
    axios.post(endpoint)
      .then(response => {
        alert(response.data.message);
      })
      .catch(error => {
        alert(`Eroare la ${actionName.toLowerCase()}.`);
      });
  };

  return (
    <div className="teams-container">
      <h2 className="title">Navigare Microsoft Teams</h2>
      <div className="button-container">
        {/* Buton pentru deschiderea Microsoft Teams */}
        <button className="button open-teams-button" onClick={() => handleNavigation('/shortcuts/teams/open-teams/', 'Deschiderea Microsoft Teams')}>
          Deschide Teams
        </button>
        {/* Buton pentru închiderea Microsoft Teams */}
        <button className="button close-teams-button" onClick={() => handleNavigation('/shortcuts/teams/close-teams/', 'Închiderea Microsoft Teams')}>
          Închide Teams
        </button>

        {/* Butoane pentru navigare în diferitele secțiuni */}
        <button className="button activity-button" onClick={() => handleNavigation('/shortcuts/teams/activity/', 'Activity')}>
          Activity
        </button>
        <button className="button chat-button" onClick={() => handleNavigation('/shortcuts/teams/chat/', 'Chat')}>
          Chat
        </button>
        <button className="button teams-button" onClick={() => handleNavigation('/shortcuts/teams/teams/', 'Teams')}>
          Teams
        </button>
        <button className="button assignments-button" onClick={() => handleNavigation('/shortcuts/teams/assignments/', 'Assignments')}>
          Assignments
        </button>
        <button className="button calendar-button" onClick={() => handleNavigation('/shortcuts/teams/calendar/', 'Calendar')}>
          Calendar
        </button>
        <button className="button calls-button" onClick={() => handleNavigation('/shortcuts/teams/calls/', 'Calls')}>
          Calls
        </button>
        <button className="button onedrive-button" onClick={() => handleNavigation('/shortcuts/teams/onedrive/', 'OneDrive')}>
          OneDrive
        </button>
      </div>
    </div>
  );
};

export default MicrosoftTeamsButton;
